/*
  Reusable vocabulary-quiz widget.

  Markup contract:
  <div class="quiz" data-quiz data-explain="shown on the correct answer">
    <p class="quiz-q">Question text…</p>
    <div class="quiz-opts">
      <button class="quiz-opt" data-correct="true">Answer</button>
      <button class="quiz-opt" data-correct="false">Distractor</button>
      …
    </div>
    <p class="quiz-feedback" data-feedback hidden></p>
  </div>

  Behavior: wrong picks are marked and stay clickable so the learner can keep
  retrieving until they land on the right answer (retry, not reveal-and-move-on).
  Once correct, all options lock and the explanation shows.
*/
(function () {
  function initQuiz(quiz) {
    var opts = Array.prototype.slice.call(quiz.querySelectorAll(".quiz-opt"));
    var feedback = quiz.querySelector("[data-feedback]");
    var solved = false;

    opts.forEach(function (opt) {
      opt.addEventListener("click", function () {
        if (solved) return;
        var correct = opt.getAttribute("data-correct") === "true";

        opts.forEach(function (o) {
          o.classList.remove("is-correct", "is-incorrect");
        });

        if (correct) {
          opt.classList.add("is-correct");
          solved = true;
          opts.forEach(function (o) { o.disabled = true; });
          feedback.textContent = quiz.getAttribute("data-explain") || "Correct.";
          feedback.classList.remove("is-wrong");
          feedback.classList.add("is-right");
          feedback.hidden = false;
        } else {
          opt.classList.add("is-incorrect");
          feedback.textContent = "Not quite — try again.";
          feedback.classList.remove("is-right");
          feedback.classList.add("is-wrong");
          feedback.hidden = false;
        }
      });
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    Array.prototype.forEach.call(document.querySelectorAll("[data-quiz]"), initQuiz);
  });
})();
